css:
@page {
  margin: 8mm 8mm 8mm;
}

.print-format {
  padding: 0 !important;
}

.print-format,
.print-format * {
  box-sizing: border-box;
}

.rt-print {
  color: #3f3a34;
  font-size: 8.8px;
  line-height: 1.18;
  orphans: 3;
  widows: 3;
}

.rt-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  gap: 14px;
  padding: 0 2px 12px;
  border-bottom: 2px solid #e8dac4;
  break-inside: avoid;
  page-break-inside: avoid;
}

.rt-brand-block {
  width: 100%;
  max-width: 62%;
  min-width: 0;
}

.rt-company-name,
.rt-client-name,
.rt-bank-name {
  font-size: 16px;
  font-weight: 700;
  color: #1f2937;
  word-break: break-word;
}

.rt-company-name {
  font-size: 13px;
  letter-spacing: 0.01em;
}

.rt-company-address,
.rt-party-address,
.rt-bank-address,
.rt-footer,
.rt-item-description,
.rt-signature-label,
.rt-terms,
.rt-muted {
  margin-top: 2px;
  font-size: 8px;
  color: #5f574d;
}

.rt-company-address,
.rt-party-address {
  line-height: 1.26;
}

.rt-company-address div,
.rt-party-address div {
  margin: 0;
  padding: 0;
}

.rt-company-legal {
  display: flex;
  flex-wrap: wrap;
  gap: 4px 10px;
  margin-top: 7px;
  padding-top: 0;
  border-top: 0;
  font-size: 9.2px;
  line-height: 1.25;
  color: #7a7063;
}

.rt-company-legal span::after {
  content: "•";
  margin-left: 10px;
  color: #b8a893;
}

.rt-company-legal span:last-child::after {
  content: "";
  margin: 0;
}

.rt-legal-row {
  display: flex;
  flex-wrap: wrap;
  gap: 4px 10px;
  margin-top: 4px;
  padding-top: 0;
  border-top: 0;
  font-size: 9.4px;
  color: #7a7063;
}

.rt-legal-row span::after {
  content: "•";
  margin-left: 10px;
  color: #b8a893;
}

.rt-legal-row span:last-child::after {
  content: "";
  margin: 0;
}

.rt-bank-address {
  line-height: 1.32;
}

.rt-meta-card {
  width: 180px;
  min-width: 180px;
  padding: 10px 12px;
  border-radius: 16px;
  border: 1px solid #e8dac4;
  background: #fcfaf6;
  break-inside: avoid;
  page-break-inside: avoid;
}

.rt-eyebrow,
.rt-section-title {
  font-size: 8px;
  font-weight: 700;
  letter-spacing: 0.16em;
  text-transform: uppercase;
  color: #9a7b53;
  break-after: avoid;
  page-break-after: avoid;
}

.rt-doc-name {
  margin: 2px 0 4px;
  font-size: 15px;
  font-weight: 800;
  line-height: 1.05;
  color: #1f2937;
  word-break: break-word;
}

.rt-meta-row,
.rt-total-row,
.rt-bank-line {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  gap: 18px;
}

.rt-meta-row,
.rt-total-row,
.rt-bank-line {
  padding: 3px 0;
  border-bottom: 1px solid #ede5d7;
  font-size: 8px;
}

.rt-meta-row:last-child,
.rt-total-row:last-child,
.rt-bank-line:last-of-type {
  border-bottom: 0;
}

.rt-meta-row span,
.rt-total-row span,
.rt-bank-line span {
  color: #8b8174;
  text-transform: uppercase;
  letter-spacing: 0.12em;
}

.rt-meta-row strong,
.rt-total-row strong,
.rt-bank-line strong,
.rt-grand-total strong {
  color: #1f2937;
  text-align: right;
  word-break: break-word;
}

.rt-client-card,
.rt-bank-card,
.rt-totals-card,
.rt-signature-card,
.rt-notes {
  margin-top: 4px;
  border-radius: 12px;
  border: 1px solid #eadfce;
  background: #fffdf9;
}

.rt-client-card,
.rt-bank-card,
.rt-signature-card,
.rt-notes {
  padding: 6px 8px;
}

.rt-client-card,
.rt-summary-grid,
.rt-signature-card,
.rt-bank-card,
.rt-totals-card {
  break-inside: avoid;
  page-break-inside: avoid;
}

.rt-items {
  width: 100%;
  margin-top: 4px;
  border-collapse: separate;
  border-spacing: 0;
  border: 1px solid #eadfce;
  border-radius: 14px;
  overflow: hidden;
  page-break-inside: auto;
}

.rt-items thead {
  display: table-header-group;
}

.rt-items tbody {
  display: table-row-group;
}

.rt-items th {
  padding: 4px 7px;
  background: #f7f2ea;
  color: #6a5d4f;
  font-size: 8.5px;
  font-weight: 700;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  border-bottom: 1px solid #eadfce;
}

.rt-items td {
  padding: 4px 7px;
  vertical-align: top;
  border-bottom: 1px solid #f1e8da;
}

.rt-items tr:last-child td {
  border-bottom: 0;
}

.rt-item-row,
.rt-item-row td,
.rt-item-description,
.rt-item-description .ql-editor,
.rt-item-description p {
  break-inside: avoid-page !important;
  page-break-inside: avoid !important;
}

.rt-col-idx {
  width: 40px;
}

.rt-col-desc {
  width: auto;
}

.rt-col-qty {
  width: 70px;
}

.rt-col-rate,
.rt-col-amount {
  width: 85px;
  text-align: right;
}

.rt-idx,
.rt-item-name {
  font-size: 8.5px;
  font-weight: 700;
  color: #1f2937;
}

.rt-idx {
  color: #9a7b53;
}

.rt-desc {
  min-width: 0;
}

.rt-item-name {
  word-break: break-word;
}

.rt-num {
  text-align: right;
  font-size: 8px;
  color: #1f2937;
}

.rt-nowrap {
  white-space: nowrap;
}

.rt-item-description .ql-editor,
.rt-item-description p,
.rt-item-description div,
.rt-item-description ul,
.rt-item-description ol,
.rt-item-description li {
  margin: 0 !important;
  padding: 0 !important;
  overflow: visible !important;
  max-height: none !important;
}

.rt-summary-grid {
  display: flex;
  gap: 10px;
  justify-content: space-between;
  margin-top: 4px;
}

.rt-bank-card {
  width: 48%;
}

.rt-bank-name {
  margin-top: 6px;
}

.rt-bank-line {
  padding: 6px 0;
}

.rt-bank-address,
.rt-bank-line,
.rt-muted {
  font-size: 9px;
}

.rt-totals-card {
  width: 48%;
  padding: 9px 11px 10px;
  background: #fcfaf6;
}

.rt-grand-total {
  display: flex;
  justify-content: space-between;
  gap: 18px;
  margin-top: 4px;
  padding: 10px 12px;
  border-radius: 12px;
  border: 1px solid #d8c3a0;
  background: #f8f1e5;
  font-size: 11px;
}

.rt-grand-total span {
  text-transform: uppercase;
  letter-spacing: 0.1em;
  color: #6a5d4f;
}

.rt-signature-grid {
  display: flex;
  gap: 10px;
  margin-top: 4px;
}

.rt-signature-box {
  width: 50%;
  padding: 6px 8px;
  border-radius: 10px;
  background: #fcfaf6;
  border: 1px solid #ede5d7;
}

.rt-signature-label {
  margin-top: 0;
  min-height: 18px;
  line-height: 1.25;
}

.rt-signature-space {
  height: 18px;
  margin-top: 6px;
  border-radius: 10px;
  background: #fff;
  border: 1px dashed #d9c8b0;
}

.rt-notes {
  margin-top: 4px;
  padding: 9px 11px 8px;
  border-radius: 12px;
  break-inside: auto !important;
  page-break-inside: auto !important;
}

.rt-terms {
  column-count: 3;
  column-gap: 8px;
  column-rule: 1px solid #efe6d8;
  column-fill: balance;
  line-height: 1.12;
  overflow: visible !important;
  max-height: none !important;
}

.rt-terms,
.rt-terms .ql-editor,
.rt-terms p,
.rt-terms li {
  font-size: 6.2px;
  line-height: 1.03;
}

.rt-terms .ql-editor,
.rt-terms div,
.rt-terms p,
.rt-terms li,
.rt-terms ul,
.rt-terms ol {
  padding: 0 !important;
  margin: 0 !important;
  break-inside: auto;
  page-break-inside: auto;
  overflow: visible !important;
  max-height: none !important;
}

.rt-footer {
  margin-top: 4px;
  padding-top: 6px;
  border-top: 1px solid #e8dac4;
  text-align: center;
}

@media print {
  .rt-summary-grid,
  .rt-signature-grid {
    display: table;
    width: 100%;
    table-layout: fixed;
    border-spacing: 10px 0;
    margin-left: -10px;
    margin-right: -10px;
  }

  .rt-bank-card,
  .rt-totals-card,
  .rt-signature-box {
    display: table-cell;
    vertical-align: top;
  }

  .rt-items {
    overflow: visible;
  }

  .rt-items tr,
  .rt-items td,
  .rt-items th {
    break-inside: avoid-page !important;
    page-break-inside: avoid !important;
  }

  .rt-terms {
    column-count: 3;
    column-gap: 8px;
    column-fill: balance;
  }
}

/* Reytinas A4 flow tuning */
.rt-footer {
  display: none !important;
}

.rt-notes {
  margin-top: 14px !important;
  break-before: page !important;
  page-break-before: always !important;
  break-inside: auto !important;
  page-break-inside: auto !important;
}

.rt-terms {
  column-count: 1 !important;
  column-gap: 0 !important;
  column-rule: 0 !important;
  column-fill: auto !important;
  overflow: visible !important;
  max-height: none !important;
}

.rt-terms,
.rt-terms .ql-editor,
.rt-terms p,
.rt-terms li {
  font-size: 10px !important;
  line-height: 1.18 !important;
}

.rt-terms .ql-editor,
.rt-terms div,
.rt-terms p,
.rt-terms li,
.rt-terms ul,
.rt-terms ol {
  margin: 0 0 2px !important;
  padding: 0 !important;
  overflow: visible !important;
  max-height: none !important;
}

html:
{% set title = "DEVIS" %}

{# -------------------------
   Société
------------------------- #}
{% set company = frappe.db.get_value(
  "Company",
  doc.company,
  ["company_name", "siret", "tax_id", "email", "phone_no", "website"],
  as_dict=True
) or {} %}

{% set company_siret = (company.siret or "") | replace(" ", "") %}
{% if company_siret and company_siret|length == 14 %}
  {% set company_siret = company_siret[:3] ~ " " ~ company_siret[3:6] ~ " " ~ company_siret[6:9] ~ " " ~ company_siret[9:] %}
{% endif %}

{% set company_address = {} %}
{% if doc.company_address %}
  {% set company_address = frappe.db.get_value(
    "Address",
    doc.company_address,
    [
      "address_line1",
      "address_line2",
      "city",
      "county",
      "state",
      "pincode",
      "country",
      "phone",
      "email_id"
    ],
    as_dict=True
  ) or {} %}
{% endif %}

{# -------------------------
   Client
------------------------- #}
{% set client = {} %}
{% if doc.quotation_to == "Customer" and doc.party_name %}
  {% set client = frappe.db.get_value(
    "Customer",
    doc.party_name,
    ["tax_id", "siret", "siren"],
    as_dict=True
  ) or {} %}
{% endif %}

{% set client_siret = (client.siret or "") | replace(" ", "") %}
{% if client_siret and client_siret|length == 14 %}
  {% set client_siret = client_siret[:3] ~ " " ~ client_siret[3:6] ~ " " ~ client_siret[6:9] ~ " " ~ client_siret[9:] %}
{% endif %}

{% set client_siren = (client.siren or "") | replace(" ", "") %}
{% if client_siren and client_siren|length == 9 %}
  {% set client_siren = client_siren[:3] ~ " " ~ client_siren[3:6] ~ " " ~ client_siren[6:] %}
{% endif %}

{% set client_address = {} %}
{% if doc.customer_address %}
  {% set client_address = frappe.db.get_value(
    "Address",
    doc.customer_address,
    [
      "address_line1",
      "address_line2",
      "city",
      "county",
      "state",
      "pincode",
      "country",
      "phone",
      "email_id"
    ],
    as_dict=True
  ) or {} %}
{% endif %}

{# -------------------------
   Banque
------------------------- #}
{% set bank_accounts = frappe.db.get_all(
  "Bank Account",
  filters={"company": doc.company, "is_company_account": 1},
  fields=["name", "bank", "iban", "bank_account_no", "branch_code"],
  limit=1
) %}
{% set bank_account = bank_accounts[0] if bank_accounts else {} %}

{% set bank = {} %}
{% if bank_account and bank_account.bank %}
  {% set bank = frappe.db.get_value(
    "Bank",
    bank_account.bank,
    ["bank_name", "swift_number"],
    as_dict=True
  ) or {} %}
{% endif %}

{% set bank_links = [] %}
{% if bank_account and bank_account.bank %}
  {% set bank_links = frappe.db.get_all(
    "Dynamic Link",
    filters={
      "link_doctype": "Bank",
      "link_name": bank_account.bank,
      "parenttype": "Address"
    },
    fields=["parent"],
    limit=1
  ) or [] %}
{% endif %}

{% set bank_address = {} %}
{% if bank_links %}
  {% set bank_address = frappe.db.get_value(
    "Address",
    bank_links[0].parent,
    ["address_line1", "address_line2", "city", "pincode", "country"],
    as_dict=True
  ) or {} %}
{% endif %}

{# -------------------------
   Helpers
------------------------- #}
{% set has_bank_info = bank_account.iban or bank_account.bank_account_no or bank.swift_number or bank_address.address_line1 or bank_address.city or bank_address.country %}
{% set taxes = doc.taxes or [] %}
{% set items = doc.items or [] %}

<section class="rt-print">

  <header class="rt-header">
    <div class="rt-brand-block">
      <div class="rt-company-name">{{ company.company_name or doc.company }}</div>

      <div class="rt-company-address">
        {% if company_address.address_line1 %}<div>{{ company_address.address_line1 }}</div>{% endif %}
        {% if company_address.address_line2 %}<div>{{ company_address.address_line2 }}</div>{% endif %}
        {% if company_address.pincode or company_address.city %}
          <div>{{ company_address.pincode or "" }}{% if company_address.pincode and company_address.city %} {% endif %}{{ company_address.city or "" }}</div>
        {% endif %}
        {% if not (company_address.pincode or company_address.city) and company_address.county %}
          <div>{{ company_address.county }}</div>
        {% endif %}
        {% if company_address.state and company_address.state != company_address.city %}
          <div>{{ company_address.state }}</div>
        {% endif %}
        {% if company_address.country %}<div>{{ company_address.country }}</div>{% endif %}
        {% if company.phone_no %}<div>{{ company.phone_no }}</div>{% elif company_address.phone %}<div>{{ company_address.phone }}</div>{% endif %}
        {% if company.email %}<div>{{ company.email }}</div>{% elif company_address.email_id %}<div>{{ company_address.email_id }}</div>{% endif %}
        {% if company.website %}<div>{{ company.website }}</div>{% endif %}
      </div>

      {% if company_siret or company.tax_id %}
        <div class="rt-company-legal">
          {% if company_siret %}<span>SIRET {{ company_siret }}</span>{% endif %}
          {% if company.tax_id %}<span>TVA {{ company.tax_id }}</span>{% endif %}
        </div>
      {% endif %}
    </div>

    <div class="rt-meta-card">
      <div class="rt-eyebrow">{{ title }}</div>
      <h1 class="rt-doc-name">{{ doc.name }}</h1>

      <div class="rt-meta-row">
        <span>Date</span>
        <strong>{{ doc.get_formatted("transaction_date") }}</strong>
      </div>

      {% if doc.valid_till %}
        <div class="rt-meta-row">
          <span>Validité</span>
          <strong>{{ doc.get_formatted("valid_till") }}</strong>
        </div>
      {% endif %}

      {% if doc.po_no %}
        <div class="rt-meta-row">
          <span>Réf. client</span>
          <strong>{{ doc.po_no }}</strong>
        </div>
      {% endif %}
    </div>
  </header>

  <section class="rt-client-card">
    <div class="rt-section-title">Client</div>
    <div class="rt-client-name">{{ doc.customer_name or doc.party_name or doc.name }}</div>

    <div class="rt-party-address">
      {% if client_address.address_line1 %}<div>{{ client_address.address_line1 }}</div>{% endif %}
      {% if client_address.address_line2 %}<div>{{ client_address.address_line2 }}</div>{% endif %}
      {% if client_address.pincode or client_address.city %}
        <div>{{ client_address.pincode or "" }}{% if client_address.pincode and client_address.city %} {% endif %}{{ client_address.city or "" }}</div>
      {% endif %}
      {% if not (client_address.pincode or client_address.city) and client_address.county %}
        <div>{{ client_address.county }}</div>
      {% endif %}
      {% if client_address.state and client_address.state != client_address.city %}
        <div>{{ client_address.state }}</div>
      {% endif %}
      {% if client_address.country %}<div>{{ client_address.country }}</div>{% endif %}
      {% if client_address.phone %}<div>{{ client_address.phone }}</div>{% endif %}
      {% if client_address.email_id %}<div>{{ client_address.email_id }}</div>{% endif %}
    </div>

    {% if client.tax_id or client_siret or client_siren %}
      <div class="rt-legal-row">
        {% if client.tax_id %}<span>TVA {{ client.tax_id }}</span>{% endif %}
        {% if client_siret %}<span>SIRET {{ client_siret }}</span>{% endif %}
        {% if client_siren %}<span>SIREN {{ client_siren }}</span>{% endif %}
      </div>
    {% endif %}
  </section>

  <table class="rt-items">
    <thead>
      <tr>
        <th class="rt-col-idx">#</th>
        <th class="rt-col-desc">Désignation</th>
        <th class="rt-col-qty">Qté</th>
        <th class="rt-col-rate">PU HT</th>
        <th class="rt-col-amount">Montant HT</th>
      </tr>
    </thead>
    <tbody>
      {% for row in items %}
        <tr class="rt-item-row">
          <td class="rt-idx">{{ row.idx }}</td>
          <td class="rt-desc">
            <div class="rt-item-name">{{ row.item_name or row.item_code }}</div>
            {% if row.description %}
              <div class="rt-item-description">{{ row.description }}</div>
            {% endif %}
          </td>
          <td class="rt-num rt-nowrap">
            {{ row.get_formatted("qty") }}{% if row.uom or row.stock_uom %} {{ row.uom or row.stock_uom }}{% endif %}
          </td>
          <td class="rt-num rt-nowrap">{{ row.get_formatted("rate", doc) }}</td>
          <td class="rt-num rt-nowrap">{{ row.get_formatted("amount", doc) }}</td>
        </tr>
      {% endfor %}
    </tbody>
  </table>

  <section class="rt-summary-grid">
    <div class="rt-bank-card">
      <div class="rt-section-title">Coordonnées bancaires</div>

      {% if has_bank_info %}
        <div class="rt-bank-name">{{ bank.bank_name or bank_account.bank or "Banque" }}</div>

        {% if bank_account.iban or bank_account.bank_account_no %}
          <div class="rt-bank-line">
            <span>IBAN</span>
            <strong>{{ bank_account.iban or bank_account.bank_account_no }}</strong>
          </div>
        {% endif %}

        {% if bank.swift_number %}
          <div class="rt-bank-line">
            <span>BIC</span>
            <strong>{{ bank.swift_number }}</strong>
          </div>
        {% endif %}

        {% if bank_address.address_line1 or bank_address.address_line2 or bank_address.pincode or bank_address.city or bank_address.country %}
          <div class="rt-bank-address">
            {% if bank_address.address_line1 %}{{ bank_address.address_line1 }}{% endif %}
            {% if bank_address.address_line2 %}<br>{{ bank_address.address_line2 }}{% endif %}
            {% if bank_address.pincode or bank_address.city %}<br>{{ bank_address.pincode or "" }} {{ bank_address.city or "" }}{% endif %}
            {% if bank_address.country %}<br>{{ bank_address.country }}{% endif %}
          </div>
        {% endif %}
      {% else %}
        <div class="rt-muted">RIB communiqué sur demande.</div>
      {% endif %}
    </div>

    <div class="rt-totals-card">
      <div class="rt-total-row">
        <span>Total HT</span>
        <strong>{{ doc.get_formatted("net_total") }}</strong>
      </div>

      {% for tax in taxes %}
        {% if tax.tax_amount %}
          <div class="rt-total-row">
            <span>{{ tax.description or tax.account_head or "Taxe" }}</span>
            <strong>{{ tax.get_formatted("tax_amount", doc) }}</strong>
          </div>
        {% endif %}
      {% endfor %}

      <div class="rt-grand-total">
        <span>Total TTC</span>
        <strong>{{ doc.get_formatted("grand_total") }}</strong>
      </div>
    </div>
  </section>

  <section class="rt-signature-card">
    <div class="rt-section-title">Bon pour accord</div>
    <div class="rt-signature-grid">
      <div class="rt-signature-box">
        <div class="rt-signature-label">Date, nom, fonction</div>
        <div class="rt-signature-space"></div>
      </div>
      <div class="rt-signature-box">
        <div class="rt-signature-label">Signature précédée de la mention « Bon pour accord »</div>
        <div class="rt-signature-space"></div>
      </div>
    </div>
  </section>

  {% if doc.terms %}
    <section class="rt-notes">
      <div class="rt-section-title">Conditions & CGV</div>
      <div class="rt-terms">{{ doc.terms }}</div>
    </section>
  {% endif %}

  <footer class="rt-footer">
    Merci pour votre confiance. Ce devis reste valable jusqu’à la date indiquée ci-dessus.
  </footer>
</section>
